-- =====================================================
-- CMS Coverage Reference Tables
-- Purpose: Real CMS reference data for LCD, NCD, prior auth, MAC contractors
-- Replaces hardcoded mock data in mcp-cms-coverage-server
-- =====================================================

-- =====================================================
-- Table: cms_lcds (Local Coverage Determinations)
-- =====================================================
CREATE TABLE IF NOT EXISTS public.cms_lcds (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  lcd_id TEXT NOT NULL UNIQUE,
  title TEXT NOT NULL,
  contractor_name TEXT,
  contractor_number TEXT,
  jurisdiction TEXT,
  status TEXT NOT NULL DEFAULT 'active',
  effective_date DATE,
  revision_date DATE,
  end_date DATE,
  related_codes TEXT[],
  coverage_indications TEXT[],
  limitations TEXT[],
  summary TEXT,
  benefit_category TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.cms_lcds ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public read access for CMS LCDs" ON public.cms_lcds FOR SELECT USING (true);
CREATE INDEX IF NOT EXISTS idx_cms_lcds_lcd_id ON public.cms_lcds(lcd_id);
CREATE INDEX IF NOT EXISTS idx_cms_lcds_status ON public.cms_lcds(status);
COMMENT ON TABLE public.cms_lcds IS 'CMS Local Coverage Determinations — real Medicare reference data';

-- =====================================================
-- Table: cms_ncds (National Coverage Determinations)
-- =====================================================
CREATE TABLE IF NOT EXISTS public.cms_ncds (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  ncd_id TEXT NOT NULL UNIQUE,
  title TEXT NOT NULL,
  manual_section TEXT,
  status TEXT NOT NULL DEFAULT 'active',
  effective_date DATE,
  implementation_date DATE,
  benefit_category TEXT,
  coverage_provisions TEXT,
  covered_indications TEXT[],
  non_covered_indications TEXT[],
  documentation_requirements TEXT[],
  related_lcd_ids TEXT[],
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.cms_ncds ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public read access for CMS NCDs" ON public.cms_ncds FOR SELECT USING (true);
CREATE INDEX IF NOT EXISTS idx_cms_ncds_ncd_id ON public.cms_ncds(ncd_id);
COMMENT ON TABLE public.cms_ncds IS 'CMS National Coverage Determinations — real Medicare reference data';

-- =====================================================
-- Table: cms_coverage_articles
-- =====================================================
CREATE TABLE IF NOT EXISTS public.cms_coverage_articles (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  article_id TEXT NOT NULL UNIQUE,
  title TEXT NOT NULL,
  article_type TEXT NOT NULL,
  related_lcd_id TEXT,
  related_codes TEXT[],
  content TEXT,
  contractor_name TEXT,
  effective_date DATE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.cms_coverage_articles ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public read access for CMS articles" ON public.cms_coverage_articles FOR SELECT USING (true);
CREATE INDEX IF NOT EXISTS idx_cms_coverage_articles_article_id ON public.cms_coverage_articles(article_id);
CREATE INDEX IF NOT EXISTS idx_cms_coverage_articles_related_lcd ON public.cms_coverage_articles(related_lcd_id);
COMMENT ON TABLE public.cms_coverage_articles IS 'CMS billing/coding coverage articles linked to LCDs';

-- =====================================================
-- Table: cms_prior_auth_codes
-- =====================================================
CREATE TABLE IF NOT EXISTS public.cms_prior_auth_codes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  code TEXT NOT NULL,
  code_system TEXT NOT NULL DEFAULT 'cpt',
  description TEXT NOT NULL,
  requires_prior_auth BOOLEAN NOT NULL DEFAULT true,
  documentation_required TEXT[],
  typical_approval_time TEXT,
  category TEXT,
  payer_type TEXT DEFAULT 'medicare',
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(code, payer_type)
);

ALTER TABLE public.cms_prior_auth_codes ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public read access for prior auth codes" ON public.cms_prior_auth_codes FOR SELECT USING (true);
CREATE INDEX IF NOT EXISTS idx_cms_prior_auth_code ON public.cms_prior_auth_codes(code);
CREATE INDEX IF NOT EXISTS idx_cms_prior_auth_category ON public.cms_prior_auth_codes(category);
COMMENT ON TABLE public.cms_prior_auth_codes IS 'Prior authorization requirements by CPT/HCPCS code';

-- =====================================================
-- Table: cms_mac_contractors
-- =====================================================
CREATE TABLE IF NOT EXISTS public.cms_mac_contractors (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  state_code TEXT NOT NULL,
  jurisdiction_type TEXT NOT NULL,
  contractor_name TEXT NOT NULL,
  contractor_number TEXT NOT NULL,
  jurisdiction_label TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(state_code, jurisdiction_type)
);

ALTER TABLE public.cms_mac_contractors ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public read access for MAC contractors" ON public.cms_mac_contractors FOR SELECT USING (true);
CREATE INDEX IF NOT EXISTS idx_cms_mac_state ON public.cms_mac_contractors(state_code);
COMMENT ON TABLE public.cms_mac_contractors IS 'Medicare Administrative Contractors by state — all 50 states + DC + PR';

