-- =====================================================
-- SEED DATA: CMS Coverage Articles (16 records)
-- =====================================================
INSERT INTO public.cms_coverage_articles (article_id, title, article_type, related_lcd_id, related_codes, content, contractor_name, effective_date)
VALUES
('A57708', 'Billing and Coding: MRI of the Brain', 'billing', 'L33777', ARRAY['70551','70552','70553'],
 'Report 70551 for MRI brain without contrast, 70553 for with and without contrast. Use modifier TC for technical component only. Common diagnoses: G43 (migraine), R51.9 (headache), G40 (epilepsy), C71 (brain neoplasm).', 'Novitas Solutions', '2024-04-01'),
('A57709', 'Billing and Coding: MRI of the Lumbar Spine', 'billing', 'L33562', ARRAY['72148','72149','72158'],
 'Report 72148 for MRI lumbar without contrast, 72158 for with and without contrast. Document 6 weeks of conservative treatment. ICD-10: M54.5 (low back pain), M54.1 (radiculopathy), M51.1 (disc herniation with radiculopathy).', 'Novitas Solutions', '2024-01-01'),
('A52509', 'Billing and Coding: PET Scans for Oncology', 'billing', 'L35028', ARRAY['78811','78812','78813','78814','78815','78816'],
 'Use 78816 for PET/CT whole body. Report with primary cancer ICD-10 code. Initial treatment strategy: no prior auth needed. Subsequent treatment strategy: document clinical change.', 'National Government Services', '2025-01-01'),
('A57426', 'Billing and Coding: CPAP and RAD', 'billing', 'L33797', ARRAY['E0601','E0470','E0471','A7027','A7028','A7029','A7030'],
 'E0601 for CPAP device rental. Include sleep study results with initial claim. Document AHI score and face-to-face evaluation. Submit compliance data at 90-day review. DX G47.33 for obstructive sleep apnea.', 'CGS Administrators', '2024-03-01'),
('A55805', 'Billing and Coding: Power Mobility Devices', 'billing', 'L33789', ARRAY['K0823','K0824','K0856','K0857','K0858','K0861'],
 'Prior authorization required for all PMDs. Submit 7-element physician order, face-to-face exam notes, PT/OT evaluation, and home assessment. K0823 for Group 2 standard power wheelchair.', 'CGS Administrators', '2024-06-01'),
('A52937', 'Coding Guidelines: Molecular Pathology', 'coding', 'L36256', ARRAY['81170','81201','81210','81211','81225','81226','81235'],
 'Report Tier 1/Tier 2 molecular codes based on specific gene and analysis type. Do not unbundle multi-gene panels. Document clinical indication for each gene tested.', 'Palmetto GBA', '2025-02-01'),
('A57891', 'Utilization Review: Outpatient Therapy Services', 'utilization', 'L34943', ARRAY['97110','97112','97116','97140','97530'],
 'KX modifier required when therapy exceeds $2,230 threshold. Document functional outcome measures. Each visit note must demonstrate skilled intervention.', 'Novitas Solutions', '2024-11-01'),
('A58102', 'Billing and Coding: Cardiac Catheterization', 'billing', 'L33224', ARRAY['93451','93452','93453','93454','93455','93456','93457','93458','93459','93460','93461'],
 'Report left heart catheterization codes separately from right heart catheterization. Include pre-procedure non-invasive testing results in documentation.', 'First Coast Service Options', '2024-04-01'),
('A58456', 'Billing and Coding: Bone Density Studies', 'billing', 'L36859', ARRAY['77078','77080','77081'],
 'Report 77080 for axial DXA. Medicare covers once per 24 months. More frequent testing covered with documented clinical change. Use modifier 26 for professional component.', 'Palmetto GBA', '2024-10-01'),
('A58789', 'Coding Guidelines: Sleep Testing', 'coding', 'L33611', ARRAY['95800','95801','95805','95806','95810','95811'],
 'Type 3 home sleep test (95806) is first-line for uncomplicated OSA. Type 1 polysomnography (95810) for complex cases. MSLT (95805) must follow nocturnal PSG.', 'CGS Administrators', '2024-07-01'),
('A59001', 'Billing and Coding: Wound Care Services', 'billing', 'L35125', ARRAY['97597','97598','97602','97605','97606','97607','97608'],
 'Selective debridement (97597/97598) reported by wound surface area. First 20 sq cm: 97597. Each additional 20 sq cm: 97598. Document wound measurements, depth, and tissue type.', 'Novitas Solutions', '2024-09-01'),
('A59234', 'Billing and Coding: Spinal Fusion', 'billing', 'L33735', ARRAY['22551','22552','22554','22612','22614','22630','22632','22633','22634'],
 'Anterior interbody fusion: 22551 (single), +22552 (each additional). Posterior fusion: 22612 (single), +22614 (each additional). Report anterior and posterior components separately.', 'Novitas Solutions', '2024-12-01'),
('A59567', 'Utilization Review: Home Oxygen Therapy', 'utilization', 'L33694', ARRAY['E1390','E1391','E0431','E0433','E0434','E0439','E0441','E0442','E0443','E0444'],
 'Qualifying ABG or oximetry required within 30 days of initial order. Recertification testing between days 61-90 mandatory. 36-month rental cap applies. Portable oxygen requires documented ambulation need.', 'Noridian Healthcare Solutions', '2024-09-01'),
('A59890', 'Billing and Coding: Epidural Steroid Injections', 'billing', 'L34995', ARRAY['62320','62321','62322','62323','64479','64480','64483','64484'],
 'Interlaminar approach: 62320/62321 (cervical/thoracic), 62322/62323 (lumbar/sacral). Transforaminal: 64479/+64480, 64483/+64484. Fluoroscopic guidance included in transforaminal codes.', 'Palmetto GBA', '2024-05-01'),
('A60123', 'Billing and Coding: ICD Implantation', 'billing', 'L33552', ARRAY['33249','33262','33263','33264','33270','33271'],
 'Report 33249 for initial ICD. Generator replacement: 33262 (single), 33263 (dual), 33264 (CRT-D). Include ACC NCDR registry data with claim. Document EF%, rhythm indication, OMT duration.', 'National Government Services', '2025-01-01'),
('A60456', 'Coding Guidelines: Bariatric Surgery', 'coding', 'L33636', ARRAY['43644','43645','43770','43775','43842','43845','43846'],
 'Roux-en-Y: 43644 (laparoscopic), 43846 (open). Sleeve gastrectomy: 43775. Adjustable gastric band: 43770 (placement). Submit BMI ICD-10 code (Z68.41-Z68.45) as secondary diagnosis.', 'National Government Services', '2024-10-01')
ON CONFLICT (article_id) DO NOTHING;

